selector_to_html = {"a[href=\"control_mod/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1 </span>Control Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Control Module \u2013 Providing a Complete Low-Level Robot Control Interface</strong></p><p>The control module is a core component of the AgiBot X2 AimDK, providing comprehensive low-level control interfaces for the robot. It follows the ROS2 standard and supports both C++ and Python, enabling developers to achieve flexible and efficient robot control.</p>", "a[href=\"control_mod/joint_control.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.6 </span>Joint Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The joint control interfaces provide precise control over each robot joint, supporting multiple control modes and joint groups.</strong></p>", "a[href=\"hal/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4 </span>Hardware Abstraction Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Hardware Abstraction Module \u2013 Provides Low-Level Hardware Interfaces and Sensor Data Access</strong></p><p>The hardware abstraction module is a foundational component of the AgiBot X2 AimDK, providing abstracted interfaces to the robot\u2019s various hardware devices. It follows the ROS2 standard and supports both C++ and Python, offering developers a unified hardware access interface.</p>", "a[href=\"perception/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.5 </span>Perception Module (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 SDK Perception Module \u2013 Provides multi-modal perception capabilities</strong></p><p>Key Features</p>", "a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5 </span><i class=\"fa fa-plug\"></i> Interface Description<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Interface Documentation \u2013 ROS2-based humanoid robot development interfaces</strong></p><p>The AgiBot X2 AimDK provides a complete set of ROS2 interfaces for controlling the AgiBot X2 humanoid robot. The interfaces follow ROS2 standards and support both C++ and Python, offering developers a flexible and efficient environment for robot application development.</p>", "a[href=\"interactor/voice.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2.1 </span>Voice Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The voice control interface provides a complete set of voice interaction capabilities, including speech synthesis, speech recognition, audio noise reduction, audio playback, and volume control.</strong></p>", "a[href=\"FASM/sudo.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.3.2 </span>Permission Management (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"control_mod/modeswitch.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.1 </span>Motion Mode Switching<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The mode-switch and locomotion interfaces provide core capabilities for switching motion modes and controlling walking/running.</strong></p>", "a[href=\"control_mod/locomotion.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.2 </span>Locomotion Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The locomotion control interfaces provide the core functions for controlling the robot\u2019s walking and running velocities.</strong></p>", "a[href=\"hal/pmu.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4.2 </span>Power Management Unit (PMU)<a class=\"headerlink\" href=\"#pmu\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The Power Management Unit interface provides monitoring and management of the robot\u2019s power system, including battery status, voltage and current monitoring, and more.</strong></p>", "a[href=\"hal/sensor.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4.1 </span>Sensor Interfaces<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The sensor interfaces provide data access and control for the robot\u2019s various sensors, including cameras, IMUs, LiDAR, and touch sensors.</strong></p>", "a[href=\"control_mod/preset_motion.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.4 </span>Preset Motion Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>Preset motion control allows the robot to execute predefined actions such as waving, handshaking, raising an arm, etc. With a simple service call, the robot can quickly perform specific actions, making this interface ideal for common interaction scenarios.</strong></p>", "a[href=\"control_mod/endeffector.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.5 </span>End Effector Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The end-effector control module currently supports:</p>", "a[href=\"FASM/fault.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.3.1 </span>Fault Handling (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"FASM/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.3 </span>Fault &amp; System Management Module (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 SDK Fault &amp; System Management Module \u2013 Providing fault diagnostics and system management capabilities</strong></p><p>The Fault &amp; System Management module is a key component of the AgiBot X2 SDK, providing fault diagnostics and system-level management capabilities. Through these interfaces, developers can promptly detect and handle robot faults, manage permissions, monitor system status, and ensure safe and stable operation.</p>", "a[href=\"interactor/screen.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2.2 </span>Screen Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The screen control interface provides full display control capabilities, including emoji playback, video playback, and more. It enables developers to implement rich visual interaction features for the robot.</strong></p>", "a[href=\"interactor/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2 </span>Interaction Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Interaction Module \u2013 providing rich human\u2013robot interaction interfaces</strong></p><p><strong>Core Features</strong></p>", "a[href=\"perception/vision.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.5.1 </span>Vision (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"control_mod/MC_control.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.3 </span>MC Control Signal Configuration<a class=\"headerlink\" href=\"#mc\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>MC control signal configuration provides unified management of multiple input sources, ensuring the robot always responds to the highest-priority control signal.</strong></p><p>Control signal configuration is one of the core features of the AgiBot X2 AimDK, enabling unified management and priority arbitration among multiple control sources. This mechanism ensures that when multiple control inputs are active, the robot safely and reliably responds to the command with the highest priority.</p>", "a[href=\"perception/SLAM.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.5.2 </span>SLAM (Coming Soon)<a class=\"headerlink\" href=\"#slam\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"interactor/lights.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2.3 </span>LED Strip Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The chest LED strip control interface provides enhanced visual interaction capabilities.</strong></p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
